import {
  Component,
  computed,
  DestroyRef,
  inject,
  OnInit,
  signal,
} from '@angular/core';
import { CommonModule } from '@angular/common';
import { ActivatedRoute, Data } from '@angular/router';
import {
  catchError,
  combineLatest,
  EMPTY,
  from,
  of,
  switchMap,
  tap,
  throwError,
} from 'rxjs';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';

// Third-party imports
import { AccordionModule } from 'primeng/accordion';
import { DividerModule } from 'primeng/divider';
import { ProgressSpinner } from 'primeng/progressspinner';

// Application imports
import { VendorResponse } from '../../../../../../api';
import { VendorDataStrategy } from '../../../../strategies';
import { AdminDetailSection } from '../../../../models';
import {
  isDefined,
  isEmpty,
  isNullOrUndefined,
} from '../../../../../../shared/utils';
import { SectionConfigBuilder } from '../../../../factories';
import { BroadcastEventMessageService } from '../../../../services/broadcast-event-messages.service';

interface VendorRouteData extends Data {
  vendor?: VendorResponse;
}

interface EntityUpdatedMessage {
  entityType: string;
  data: VendorResponse;
}

@Component({
  selector: 'app-vendor-details-container',
  imports: [AccordionModule, DividerModule, ProgressSpinner, CommonModule],
  templateUrl: './vendor-details-container.component.html',
  styleUrl: './vendor-details-container.component.scss',
})
export class VendorDetailsContainerComponent implements OnInit {
  private readonly broadcastService = inject(BroadcastEventMessageService);
  protected informationSections = signal<AdminDetailSection[]>([]);
  protected settingsSections = signal<AdminDetailSection[]>([]);
  protected statisticsSections = signal<AdminDetailSection[]>([]);
  protected loading = signal(true);
  protected entity = signal<VendorResponse | null>(null);
  protected error = signal<string | null>(null);
  protected defaultExpandedSections = 0;

  // Helper computed properties
  protected hasInformationSections = computed(
    () => this.informationSections().length > 0,
  );
  protected hasSettingsSections = computed(
    () => this.settingsSections().length > 0,
  );
  protected hasStatisticsSections = computed(
    () => this.statisticsSections().length > 0,
  );

  // Services
  private readonly dataStrategy = inject(VendorDataStrategy);
  private readonly destroyRef = inject(DestroyRef);
  private readonly route = inject(ActivatedRoute);

  private isEntityUpdatedMessage(
    message: unknown,
  ): message is EntityUpdatedMessage {
    return (
      isDefined(message) &&
      message !== null &&
      typeof message === 'object' &&
      'entityType' in message &&
      'data' in message &&
      (message as EntityUpdatedMessage).entityType === 'vendor'
    );
  }
  ngOnInit(): void {
    this.initializeEntityData();
    this.broadcastService
      .on('entity-updated')
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe((message) => {
        if (this.isEntityUpdatedMessage(message)) {
          this.entity.set(message.data);
          this.updateSectionsWithEntityData();
        }
      });
  }

  private initializeEntityData(): void {
    combineLatest([
      this.route.paramMap,
      this.route.parent?.parent?.data || of<VendorRouteData>({}),
    ])
      .pipe(
        takeUntilDestroyed(this.destroyRef),
        tap(() => {
          this.loading.set(true);
          this.setupSectionStructure();
        }),
        switchMap(([params, data]) => {
          const vendorId = params.get('vendorId');

          if (!isEmpty(data['vendor'])) {
            return of(data['vendor']);
          }

          if (isDefined(vendorId)) {
            return from(this.dataStrategy.fetchById(vendorId));
          }

          return throwError(() => new Error('Vendor ID not found'));
        }),
        catchError(() => {
          this.error.set('Failed to load vendor data');
          return EMPTY;
        }),
        tap((vendorData) => {
          this.entity.set(vendorData);
          this.loading.set(false);
          this.updateSectionsWithEntityData();
        }),
      )
      .subscribe();
  }

  private setupSectionStructure(): void {
    // Register information sections
    this.informationSections.set(
      SectionConfigBuilder.createVendorInformationSections(null),
    );

    // Register settings sections
    this.settingsSections.set(
      SectionConfigBuilder.createVendorSettingsSections(null),
    );
  }

  private updateSectionsWithEntityData(): void {
    const entityData = this.entity();
    if (isNullOrUndefined(entityData)) return;

    // Update sections with entity data
    this.informationSections.set(
      SectionConfigBuilder.createVendorInformationSections(entityData),
    );

    this.settingsSections.set(
      SectionConfigBuilder.createVendorSettingsSections(entityData),
    );
  }

  // Method for child components to save data
  async updateEntity(updates: Partial<VendorResponse>): Promise<void> {
    const vendor = this.entity();
    if (isNullOrUndefined(vendor)) return;

    try {
      this.loading.set(true);
      const updatedEntity = await this.dataStrategy.update(vendor.id, updates);
      this.entity.set(updatedEntity);
    } catch (error) {
      this.error.set(
        `${error instanceof Error ? error.message : String(error)}`,
      );
    } finally {
      this.loading.set(false);
    }
  }

  // Helper method to combine inputs
  protected getSectionInputs(
    section: AdminDetailSection,
  ): Record<string, unknown> {
    return {
      ...section.componentInputs,
      /*   saveHandler: (data: Partial<VendorResponse>) => this.updateEntity(data), */
    };
  }
}
